1	export type Customer = { yearsWithMHPCO: number };
2	export type Item = {
3	  type: string;
4	  material?: string;
5	  enchantment?: number;
6	  cursed?: boolean;
7	};
8	export type Damage = { itemType: string; amount: number };
9	export type Incident = { cause: string; damages: Damage[] };
10	export type QuoteStep = { op: "quote"; items: Item[] };
11	export type ClaimStep = { op: "claim"; policy: number; incident: Incident };
12	export type Step = QuoteStep | ClaimStep;
13	export type Scenario = { customer: Customer; steps: Step[] };
14	export type QuoteResult = { premium: number };
15	export type ClaimResult = { payout: number; remainingCap: number };
16	export type ScenarioResult = { results: (QuoteResult | ClaimResult)[] };
17	
18	const PROCESSING_FEE = 5;
19	const FIRST_INSURANCE_RATE = 0.1;
20	
21	const BASE_PREMIUMS: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	  staff: 80,
25	  potion: 40,
26	  rune: 25,
27	  moonstone: 25,
28	};
29	
30	const baseFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
31	
32	const BLOCK_OF_3_PREMIUM = 60;
33	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
34	
35	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
36	
37	const componentBlockBase = (count: number, type: string): number =>
38	  count === 3 ? BLOCK_OF_3_PREMIUM : count * baseFor({ type });
39	
40	const componentsBase = (components: Item[]): number => {
41	  const countsByType = components.reduce<Record<string, number>>((counts, item) => {
42	    counts[item.type] = (counts[item.type] ?? 0) + 1;
43	    return counts;
44	  }, {});
45	  return Object.entries(countsByType).reduce(
46	    (sum, [type, count]) => sum + componentBlockBase(count, type),
47	    0,
48	  );
49	};
50	
51	const sumBasePremiums = (items: Item[]): number => {
52	  const components = items.filter(isComponent);
53	  const standaloneBase = items
54	    .filter((item) => !isComponent(item))
55	    .reduce((sum, item) => sum + baseFor(item), 0);
56	  return componentsBase(components) + standaloneBase;
57	};
58	
59	const CURSE_RATE = 0.5;
60	const HIGH_ENCHANTMENT_RATE = 0.3;
61	const HIGH_ENCHANTMENT_THRESHOLD = 5;
62	
63	const isCursed = (item: Item): boolean => item.cursed === true;
64	const hasHighEnchantment = (item: Item): boolean =>
65	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
66	
67	const surchargeFor = (item: Item): number => {
68	  const base = baseFor(item);
69	  const curse = isCursed(item) ? base * CURSE_RATE : 0;
70	  const highEnch = hasHighEnchantment(item) ? base * HIGH_ENCHANTMENT_RATE : 0;
71	  return curse + highEnch;
72	};
73	
74	const itemSurcharges = (items: Item[]): number =>
75	  items.reduce((sum, item) => sum + surchargeFor(item), 0);
76	
77	const LOYALTY_RATE = 0.2;
78	const LOYALTY_THRESHOLD_YEARS = 2;
79	const FOLLOWUP_CONTRACT_RATE = 0.15;
80	
81	const isLoyal = (customer: Customer): boolean =>
82	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
83	
84	const loyaltyDiscount = (itemsBase: number, customer: Customer): number =>
85	  isLoyal(customer) ? itemsBase * LOYALTY_RATE : 0;
86	
87	const followupDiscount = (itemsBase: number, quoteIndex: number): number =>
88	  quoteIndex > 0 ? itemsBase * FOLLOWUP_CONTRACT_RATE : 0;
89	
90	const totalDiscounts = (itemsBase: number, customer: Customer, quoteIndex: number): number =>
91	  loyaltyDiscount(itemsBase, customer) + followupDiscount(itemsBase, quoteIndex);
92	
93	const quotePremium = (items: Item[], customer: Customer, quoteIndex: number): number => {
94	  const itemsBase = sumBasePremiums(items);
95	  const surcharges = itemSurcharges(items);
96	  const firstInsurance = itemsBase * FIRST_INSURANCE_RATE;
97	  const discounts = totalDiscounts(itemsBase, customer, quoteIndex);
98	  return Math.ceil(itemsBase + surcharges + firstInsurance - discounts + PROCESSING_FEE);
99	};
100	
101	const INSURANCE_VALUES: Record<string, number> = {
102	  sword: 1000,
103	  amulet: 600,
104	  staff: 800,
105	  potion: 400,
106	  rune: 250,
107	  moonstone: 250,
108	};
109	
110	const insuranceValueFor = (item: Item): number => INSURANCE_VALUES[item.type] ?? 0;
111	
112	const insuranceSum = (items: Item[]): number =>
113	  items.reduce((sum, item) => sum + insuranceValueFor(item), 0);
114	
115	const DEDUCTIBLE = 100;
116	const CAP_MULTIPLIER = 2;
117	const CLAIM_HIGH_ENCHANTMENT_THRESHOLD = 8;
118	const CLAIM_HIGH_ENCHANTMENT_RATE = 0.5;
119	
120	const reimbursableAmount = (item: Item, damageAmount: number): number =>
121	  (item.enchantment ?? 0) >= CLAIM_HIGH_ENCHANTMENT_THRESHOLD
122	    ? damageAmount * CLAIM_HIGH_ENCHANTMENT_RATE
123	    : damageAmount;
124	
125	const payoutForDamage = (item: Item, damageAmount: number): number =>
126	  reimbursableAmount(item, damageAmount) - DEDUCTIBLE;
127	
128	const findPolicyItem = (items: Item[], itemType: string): Item =>
129	  items.find((item) => item.type === itemType) as Item;
130	
131	const totalPayout = (damages: Damage[], policyItems: Item[]): number =>
132	  damages.reduce(
133	    (sum, damage) => sum + payoutForDamage(findPolicyItem(policyItems, damage.itemType), damage.amount),
134	    0,
135	  );
136	
137	const claimResult = (incident: Incident, policyItems: Item[]): ClaimResult => {
138	  const cap = insuranceSum(policyItems) * CAP_MULTIPLIER;
139	  const payout = totalPayout(incident.damages, policyItems);
140	  return { payout, remainingCap: cap - payout };
141	};
142	
143	export const runScenario = (scenario: Scenario): ScenarioResult => {
144	  const policies: Item[][] = [];
145	  const results = scenario.steps.map((step) => {
146	    if (step.op === "quote") {
147	      const premium = quotePremium(step.items, scenario.customer, policies.length);
148	      policies.push(step.items);
149	      return { premium };
150	    }
151	    return claimResult(step.incident, policies[step.policy]);
152	  });
153	  return { results };
154	};
